// Script Template: condition_group
// 入力モジュールの出力値をグループ番号に分類（多段分岐用）
// プレースホルダー: OpenAI_確認_診療科 = 入力元モジュール名（OpenAI モジュール）
// プレースホルダー: {"リハビリ": "1", "小児科": "1", "健診センター": "1", "耳鼻咽喉科": "1", "総合診療科": "1", "整形外科": "1", "わからない": "1"} = 値→グループ番号の JSON オブジェクト
// プレースホルダー: 2 = マッピングに該当しない場合のデフォルトグループ番号
// 出力: グループ番号文字列（"1", "2", ... "10"）

var input = $runner.getModuleResult("OpenAI_確認_診療科");
var mapping = {"リハビリ": "1", "小児科": "1", "健診センター": "1", "耳鼻咽喉科": "1", "総合診療科": "1", "整形外科": "1", "わからない": "1"};
var group = mapping[input];
if (!group) { group = "2"; }
$runner.setResult(group);

// Script Template: condition_group
// 入力モジュールの出力値をグループ番号に分類（多段分岐用）
// プレースホルダー: OpenAI_変更_診療科 = 入力元モジュール名（OpenAI モジュール）
